//-------------------------------------------------------------------------
// Dataset DEBUG  -> To-Be 삭제 (dataSet 등 10/15)
//-------------------------------------------------------------------------

scwin.onpageload = function() {
    const codeOptions_lc_unit = [
        { grpCd : "CO012", compID : "lc_unit"}
    ];
    $c.data.setCommonCode(codeOptions_lc_unit);

    scwin.vLoginCoCd = $c.data.getMemInfo("coCd");  // 소속 자회사  
    scwin.vLoginCoClsCd = $c.data.getMemInfo("coClsCd");  // 회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd"); // 사용자소속구분코드 
    scwin.vPrivAdmin = $c.data.getMemInfo("privAdmin");

	$c.gus.cfDisableKey();

	scwin.f_FieldClear();
};

//-------------------------------------------------------------------------
// UDC값
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
	ed_srchAcctDeptCd.setValue("00000");
	ed_srchAcctDeptNm.setValue("전사");
    lc_unit.setSelectedIndex(1);
    scwin.f_setCompanyInfo();
    $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);
};

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.ondataload = function() {      
    scwin.f_SetDefaultUnit();
}

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit= function () {
    var rcnt =  dlt_commonCodeCO012.getRowCount();
    if (rcnt < 1) return;
    var index = 0;
    for (i=0; i < rcnt; i++) {  
        if (dlt_commonCodeCO012.getCellData(i, "fltrCd1") == DGlobalValue.TRUE) {
           index = i;
           break;
       }
    }
    lc_unit.setSelectedIndex(index);    
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {	
    $c.gus.cfInitObjects(tbl_search,[ed_srchCloseYm, lc_version]);
	scwin.f_SetSrchDefault();
    // chk_lowerDeptIncluYn.checkAll(false);
    // chk_distYn.checkAll(false);
    // chk_dpctYn.checkAll(false);
    // scwin.f_SetGridFormat(ed_srchCloseYm.getValue().trim());
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = async function () { 
    $c.gus.cfInitHidVal(tbl_search);
    ed_srchCloseYm.setValue(scwin.fromDate_YyMm);
	await scwin.f_CloseYm();
	await scwin.f_GetVersion();
    scwin.f_SetGridFormat(ed_srchCloseYm.getValue().trim()); 
    lc_acctDeptCd.setDisabled(true);
    ed_srchAcctDeptCd.setValue("00000");
	ed_srchAcctDeptNm.setValue("전사");
     if (scwin.f_IsPopUp(ed_srchAcctDeptCd, ed_srchAcctDeptNm)) scwin.f_deptPopUp();

    chk_lowerDeptIncluYn.checkAll(false);
    chk_distYn.checkAll(false);
    chk_dpctYn.checkAll(false);
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정   --> scwin.onUdcCompleted = function() 에서 호출
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {

    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
	$c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);   

    if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
		scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
		scwin.vLoginCoClsCd =  ACConstants.CO_CLS_CD_DONGBU ;
	}
    if (scwin.vLoginCoCd =="") {
         ed_coCd.setValue("000");
         ed_coNm.setValue("동원로엑스(주)");
    } else {
        ed_coCd.setValue(scwin.vLoginCoCd);
        if(scwin.vLoginCoCd=="000") { 
            ed_coNm.setValue("동원로엑스(주)"); 
        } else {
           scwin.f_PopUpCompanyInfo('T'); 	     
        }
    } 
	// $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);    
}   

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    scwin.param = "04";
    scwin.check = pWinCloseTF;
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc
                        , ed_coCd.getValue()
                        , ed_coNm.getValue()                        
                        , scwin.check                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , scwin.param                     // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , "F"                     // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );
}

//-------------------------------------------------------------------------
// 회사 입력 팝업  callBackFunc
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function(ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ed_coCd.setValue(ret[0]);  // 코드
        ed_coNm.setValue(ret[5]);  // 회사명
    } else {
        ed_coCd.setValue("");  // 코드
        ed_coNm.setValue("");  // 회사명
    }
    // 자회사 회계 시스템(?-txtCoClsCd : As-Is HiddenField였음 )
    if (ed_coCd.getValue() > ACConstants.CO_CLS_CD_DONGBU) {        
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }    
};

//-------------------------------------------------------------------------
// 해당월의 실적이 있는지 여부 확인(True:테이타가 있음, False:데이타가 없음)
// 해당월의 실적이 없을경우 누적으로 해서 보여주므로 당월 마이너스 실적 나오는것을 막기위함 함수.
// As-Is 삭제 function임 - 호출하는 곳 없음
//-------------------------------------------------------------------------
scwin.f_CountRow = function () {
    dma_tempCount.set("sysCd", "ManagementProfitAndLossEBC");
    dma_tempCount.set("queryId", "retrieveManagementProfitAndLossCountBizDom");
    dma_tempCount.set("param1", lc_version.getValue()); 
    dma_tempCount.set("param2", ed_srchCloseYm.getValue().trim()); 
    dma_tempCount.set("param3", ed_coCd.getValue().trim()); 

    $c.sbm.execute(sbm_tempCount);
//   	ds_search.setValue(ds_search.getRowPosition(), "eisAcctDeptCd", "1");
}

//-------------------------------------------------------------------------
// 마지막 마감년월를 구한다.
//-------------------------------------------------------------------------	
scwin.f_CloseYm = function () {
    dma_closeYm.set("sysCd", "ManagementProfitAndLossEBC");
    dma_closeYm.set("queryId", "retrieveManagementProfitAndLossCloseYm"); 
	dma_closeYm.set("param3", "000");
    $c.sbm.execute(sbm_closeYm);
}	

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
	scwin.gSrchGb = "1";
    scwin.f_SetGridFormat(ed_srchCloseYm.getValue().trim());
    let vAcctDeptCd = "";

    if( ed_srchAcctDeptCd.getValue() == lc_acctDeptCd.getValue() ) {
        vAcctDeptCd = ed_srchAcctDeptCd.getValue();
    } else {
        vAcctDeptCd = lc_acctDeptCd.getValue();
    }

    dma_search.set("closeYm", ed_srchCloseYm.getValue());
    dma_search.set("lowerDeptIncluYn", scwin.tldily);  // 하위부서포함
    dma_search.set("dpctYn", scwin.tDpct);  // 하위부서포함
    dma_search.set("distYn", scwin.tDist);  // 타법인포함
    dma_search.set("coCd", ed_coCd.getValue()); 
    dma_search.set("ver", lc_version.getValue()); 
    dma_search.set("bizDomCd", ed_bizDomCd.getValue()); 
    dma_search.set("acctDeptCd", vAcctDeptCd);

//	ds_search.UseChangeInfo = false; 확인요 10/15

    $c.sbm.execute(sbm_master);
}

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = function(e) {
    var param = ",04";
    var check = $c.gus.cfIsNull(ed_srchAcctDeptCd.getValue()) ? "F" : "T"; 
	var pW = "410";

    //<--<수정_070105_신종민> 귀속변경에 따른 병행처리 수정
    if ( ed_srchCloseYm.getValue().substring(0,4).trim() == "2006" ){
        udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfoBef");
    }else{
        udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfo");
    };


    udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc
                                , ed_srchAcctDeptCd.getValue()
                                , ""
                            , check                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                            , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                            , null                            // Title순서
                            , null                            // 보여주는 각 컬럼들의 폭
                            , null                            // 컬럼중에서 숨기는 컬럼 지정
                            , ",,,,,,,,,"+ed_coCd.getValue()                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                            , pW                              // POP-UP뛰을때 원도우의 사용자 정의 폭
                            , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                            , null                            // 윈도우 위치 Y좌표
                            , null                            // 윈도우 위치 X좌표
                            , null                            // 중복체크여부	("F")
                            , null                             // 전체검색허용여부	("F")
                            , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                            ); 
}

scwin.udc_acctDeptCd_callBackFunc = function (ret) {
    scwin.tacctDeptLvl = 0;
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_srchAcctDeptCd.setValue(ret[0]);
        ed_srchAcctDeptNm.setValue(ret[1]);
		scwin.tacctDeptLvl = ret[6];
        dma_search.set("acctDeptLvl", ret[6]);
        lc_acctDeptCd.setValue(ret[0]);
        scwin.p_acctDeptCd = ret[0];
	} else {
		dma_search.set("acctDeptLvl", 0);
        scwin.tacctDeptLvl = 0;
        dma_search.set("acctDeptLvl", 0);
        lc_acctDeptCd.setValue("");
        scwin.p_acctDeptCd = "";
	}  
}

//-------------------------------------------------------------------------
// 사업영역코드팝업
//-------------------------------------------------------------------------
scwin.f_BizDomPopUp = function(e) {
    var check = $c.gus.cfIsNull(ed_bizDomCd.getValue()) ? "F" : "T";
	var pW = "410";
    udc_bizDomCd.setSelectId("retrieveBizDomCdInfo");
    udc_bizDomCd.cfCommonPopUp(scwin.udc_bizDomCd_callBackFunc
                            , ed_bizDomCd.getValue()
                            , ""
                            , check                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                            , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                            , null                            // Title순서
                            , null                            // 보여주는 각 컬럼들의 폭
                            , null                            // 컬럼중에서 숨기는 컬럼 지정
                            , ",,"                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                            , pW                              // POP-UP뛰을때 원도우의 사용자 정의 폭
                            , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                            , null                            // 윈도우 위치 Y좌표
                            , null                            // 윈도우 위치 X좌표
                            , null                            // 중복체크여부	("F")
                            , null                             // 전체검색허용여부	("F")
                            , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                            ); 
}

scwin.udc_bizDomCd_callBackFunc = function(ret) {
    $c.gus.cfSetReturnValue(ret, ed_bizDomCd, ed_bizDomNm);
    if (ret != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_bizDomCd.setValue(ret[0]);
        ed_bizDomNm.setValue(ret[1]);        
	}         
}

//-------------------------------------------------------------------------
// 버전정보를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetVersion = function () {
    dma_version.set("sysCd", "CommonEBC" );
    dma_version.set("queryId", "retrieveVersionInfo");
    dma_version.set("param1", ed_srchCloseYm.getValue());

    $c.sbm.execute(sbm_version);
}

//-------------------------------------------------------------------------
// 실적부서를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetRsltsDept = function () {

    dma_search.set("closeYm", ed_srchCloseYm.getValue());
    dma_search.set("lowerDeptIncluYn", scwin.tldily);  // 하위부서포함
    dma_search.set("distYn", scwin.tDist);  // 배부포함    
    dma_search.set("dpctYn", scwin.tDpct);  // 타법인포함
    dma_search.set("coCd", ed_coCd.getValue()); 
    dma_search.set("ver", lc_version.getValue()); 
    dma_search.set("bizDomCd", ed_bizDomCd.getValue());   

    dma_search.set("closeYm", ed_srchCloseYm.getValue());
    dma_search.set("acctDeptCd", ed_srchAcctDeptCd.getValue());
//    dma_search.set("bookClsCd",""); 
//    dma_search.set("acctDeptLvl",); 

    dma_dept.set("sysCd", "ManagementProfitAndLossEBC");

    if($c.gus.cfIsNull(ed_bizDomCd.getValue())) {

        dma_dept.set("queryId", "retrievePlanComparisonResultsAcctDept");
    } else {

        dma_dept.set("queryId", "retrievePlanComparisonResultsBizDom");
    }
    dma_dept.set("param1", ed_srchAcctDeptCd.getValue());
    dma_dept.set("param2", ed_srchCloseYm.getValue());
    dma_dept.set("param3", dma_search.get("lowerDeptIncluYn"));
    dma_dept.set("param4", dma_search.get("acctDeptLvl"));							 
    dma_dept.set("param6", scwin.tDpct);
    dma_dept.set("param7", ed_coCd.getValue());

	if (ed_bizDomCd.getValue() == ""){
        dma_dept.set("param5", dma_search.get("ver"));
    } else {
		dma_dept.set("param5", ed_bizDomCd.getValue());
    } 
    $c.sbm.execute(sbm_dept);
}

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function () {
	if (ds_version.getRowCount() < 1) return;

	var index = 0;
	for (i=0; i < ds_version.getRowCount(); i++) {
		if (ds_version.getCellData(i, "col3") == DGlobalValue.TRUE) {
			index = i;
			break;
		}
	}
	lc_version.setSelectedIndex(index);
}

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit = function () {
	if (ds_unit.getRowCount() < 1) return;

	let index = 0;
	for (i=0; i < ds_unit.getRowCount(); i++) {
		if (ds_unit.getCellData(i, "fltrCd1") == DGlobalValue.TRUE) {
			index = i;
			break;
		}
	}
	lc_unit.setSelectedIndex(1);
}

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
   if(gr_master.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let str1 = $c.gus.cfGetFormatStr(ed_srchCloseYm.getValue().trim(), "######");

    let infoArr = []

    const options = {
