scwin.f_SetGridFormat = function (pCloseYm) {
    let v_thisMm = pCloseYm.substring(4,6) + " 당월";
    let v_cum = pCloseYm.substring(4,6) + " 누계";

    gr_master.setHeaderValue("thisMm", v_thisMm);
    gr_master.setHeaderValue("cum", v_cum);
    gr_master.initGrid();        
}

