            try { if(scwin.sellAmt4 == 0) { ds_master.setCellData(scwin.i,"thisRsltsAmt"  , 0); } else {ds_master.setCellData(scwin.i,"thisRsltsAmt"  , ( scwin.variableAmt4 / scwin.sellAmt4) * scwin.cunit * 100 ); }} catch(e) {  ds_master.setCellData(scwin.i,"thisRsltsAmt"  , 0); };
            try { if(scwin.sellAmt6 == 0) { ds_master.setCellData(scwin.i,"sumBfyyThisAmt", 0); } else {ds_master.setCellData(scwin.i,"sumBfyyThisAmt", ( scwin.variableAmt6 / scwin.sellAmt6) * scwin.cunit * 100 ); }} catch(e) {  ds_master.setCellData(scwin.i,"sumBfyyThisAmt", 0); };
            try { if(scwin.sellAmt7 == 0) { ds_master.setCellData(scwin.i,"sumPlanAmt"    , 0); } else {ds_master.setCellData(scwin.i,"sumPlanAmt"    , ( scwin.variableAmt7 / scwin.sellAmt7) * scwin.cunit * 100 ); }} catch(e) {  ds_master.setCellData(scwin.i,"sumPlanAmt"    , 0); };
            try { if(scwin.sellAmt8 == 0) { ds_master.setCellData(scwin.i,"sumRsltsAmt"   , 0); } else {ds_master.setCellData(scwin.i,"sumRsltsAmt"   , ( scwin.variableAmt8 / scwin.sellAmt8) * scwin.cunit * 100 ); }} catch(e) {  ds_master.setCellData(scwin.i,"sumRsltsAmt"   , 0); };
        // debugger;
            // 당월증감
            ds_master.setCellData(scwin.i,"befDiffer"   , $c.num.parseFloat( ds_master.getCellData(scwin.i,"thisRsltsAmt") ) - $c.num.parseFloat( ds_master.getCellData(scwin.i,"bfyyThisAmt"   )));
            ds_master.setCellData(scwin.i,"thisDiffer"  , $c.num.parseFloat( ds_master.getCellData(scwin.i,"thisRsltsAmt") ) - $c.num.parseFloat( ds_master.getCellData(scwin.i,"thisPlanAmt"   )));
            // 누계증감
            ds_master.setCellData(scwin.i,"sumBefDiffer", $c.num.parseFloat( ds_master.getCellData(scwin.i,"sumRsltsAmt" ) ) - $c.num.parseFloat( ds_master.getCellData(scwin.i,"sumBfyyThisAmt")));
            ds_master.setCellData(scwin.i,"sumDiffer"   , $c.num.parseFloat( ds_master.getCellData(scwin.i,"sumRsltsAmt" ) ) - $c.num.parseFloat( ds_master.getCellData(scwin.i,"sumPlanAmt"    )));
        }

        // 년 목표대비 달성도 (requestAmt)

        ds_master.setCellData(scwin.i, "requestAmt", ""); // AS-IS와 동일하게 비표시
        // AS-IS: 4100000, 4900000, 6700000 행에서만 계산, 나머지는 공란
        if (scwin.mAcctcd== "4100000" || scwin.mAcctcd == "4900000" || scwin.mAcctcd == "6700000") {
            scwin.plan = ds_master.getCellData(scwin.i, "yearPlanAmt");
            scwin.sumRslt = ds_master.getCellData(scwin.i, "sumRsltsAmt");                     
            scwin.ach = 0;
        //    if (scwin.plan && isFinite(scwin.plan)) {
            try { if (scwin.plan == 0) {
                    scwin.ach = 0;
                } else {
                    scwin.ach = ((scwin.sumRslt / scwin.plan) * 10000)/100;                         
                }} catch(e) { 
                    scwin.ach = 0;
                }  // 소수 1자리            
                ds_master.setCellData(scwin.i, "requestAmt", scwin.ach);                                 
        }
    }
}

