scwin.ds_master_ondataload = async function (e) {

    let rowCnt = ds_master.getTotalRow();
    totalRows.setValue(rowCnt);    

	if( rowCnt == 0 ) {
        ds_master.removeAll();
        gr_master.initGrid();
	    if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    }else{
	 		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
        lc_acctDeptCd.setDisabled(true);
        return;
	} else {
        lc_acctDeptCd.setDisabled(false);
    } 

    if (rowCnt > 0) {
        var mAcctcd = "";
		for (var i=0; i<= rowCnt; i++) { 
            mAcctcd = ds_master.getCellData(i, "mgntAcctCd"); 
			 //매출원가율, 영업이익율, 경상이익율, 회계원가율, 자산비용율, 변동비율
			if ((mAcctcd == "9300001") || (mAcctcd == "9300002") || (mAcctcd == "9300003") || (mAcctcd == "9300004") || (mAcctcd == "9300005") || (mAcctcd == "9300006")) {
                gr_master.setRowBackgroundColor(i, "yellow");        
            }
        }    			
       ds_master.sort("prtPosSeq", 0); 
    } 

    if(lc_unit.getValue() == "01") {
        await scwin.f_SetGridUnit();
        await scwin.f_Rate();
    } else {
        await scwin.f_Rate();
        await scwin.f_SetGridUnit();
    }

    gr_master.setFocusedCell(0, 0);
};

